void mergeSortedArrays(int* first, int n, int* second, int m, int* mergedArray) {
    int i = 0, j = 0, k = 0;

    // Merge the arrays while both have elements remaining
    while (i < n && j < m) {
        if (first[i] <= second[j]) {
            mergedArray[k++] = first[i++];
        } else {
            mergedArray[k++] = second[j++];
        }
    }

    // If any elements are left in first, add them to mergedArray
    while (i < n) {
        mergedArray[k++] = first[i++];
    }

    // If any elements are left in second, add them to mergedArray
    while (j < m) {
        mergedArray[k++] = second[j++];
    }
}

int main() {
    int n, m;
    scanf("%d", &n);
    int* first = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &first[i]);
    }

    scanf("%d", &m);
    int* second = (int*)malloc(m * sizeof(int));
    for (int i = 0; i < m; i++) {
        scanf("%d", &second[i]);
